import { Anthropic } from '@anthropic-ai/sdk';
import { VexClient } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-key' });
const vex = new VexClient('your-vex-key');

async function secureAgentAction() {
  const message = await anthropic.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1024,
    tools: [{ name: 'execute_firewall_rule', inputSchema: {} }],
    messages: [{ role: 'user', content: 'Isolate compromised host' }]
  });

  const verification = await vex.verify({
    trace: message,
    policy: 'human_approval_critical',
    context: { action: 'firewall_change', severity: 'critical' }
  });

  if (verification.approved && verification.humanApproved) {
    console.log('Executing verified action:', message.content);
  }
}
